# --- plot helper (hidden) — muzzle speed vs barrel length ---
# Each tank's curve plots the student's OWN air_muzzle_velocity at many barrel
# lengths (which in turn uses their gas_pressure). Falls back to the built-in
# model per curve until the student's functions work.
__PATM = 100000.0

def __gp(P0, V0, A, d):
    return P0 * V0 / (V0 + A * d)

def __muzzle_ref(P0, V0, A, m, barrel, dt):
    d = 0.0
    v = 0.0
    for _ in range(2000000):
        a = (__gp(P0, V0, A, d) - __PATM) * A / m
        v += a * dt
        d += v * dt
        if d >= barrel:
            break
        if v <= 0:
            break
    return v

def __sweep_student(P0, V0, A, m, dt):
    pts = []
    b = 0.05
    while b <= 1.0 + 1e-9:
        y = air_muzzle_velocity(P0, V0, A, m, b, dt)   # <- the STUDENT's function
        pts.append([round(b, 3), round(y, 3)])
        b += 0.025
    return pts

def __sweep_ref(P0, V0, A, m, dt):
    pts = []
    b = 0.05
    while b <= 1.0 + 1e-9:
        pts.append([round(b, 3), round(__muzzle_ref(P0, V0, A, m, b, dt), 3)])
        b += 0.025
    return pts

def __plot(P0, A, m, dt):
    series = []
    for V0, label, hot in ((0.00004, "tank 40 cm³", True), (0.00008, "tank 80 cm³", False)):
        try:
            pts = __sweep_student(P0, V0, A, m, dt)
            if pts and len(pts) > 1:
                series.append({"name": label, "points": pts, "highlight": hot})
                continue
        except Exception:
            pass
        series.append({"name": label, "points": __sweep_ref(P0, V0, A, m, dt), "highlight": hot})
    return series
